# Phase 8 Task 1: Temp Directory and Image IPC

## CONTEXT
Phase 8 adds image support to ClaudeCAD. Users can paste reference images, and the app captures viewport screenshots. All images are saved to a temp directory and referenced by file path when sending to Claude CLI.

This task sets up the foundation: temp directory management and IPC handlers for saving images.

## REQUIREMENTS

### 1. Temp Directory Setup (main.js)

Create temp directory on app start:

```javascript
const os = require('os');
const path = require('path');
const fs = require('fs');

const TEMP_IMAGE_DIR = path.join(os.tmpdir(), 'claudecad-images');
let imageCounter = 0;

function ensureTempDir() {
  if (!fs.existsSync(TEMP_IMAGE_DIR)) {
    fs.mkdirSync(TEMP_IMAGE_DIR, { recursive: true });
  }
}

function clearTempDir() {
  if (fs.existsSync(TEMP_IMAGE_DIR)) {
    const files = fs.readdirSync(TEMP_IMAGE_DIR);
    for (const file of files) {
      fs.unlinkSync(path.join(TEMP_IMAGE_DIR, file));
    }
  }
  imageCounter = 0;
}
```

Call `ensureTempDir()` in app ready handler. Call `clearTempDir()` on app quit.

### 2. Image Downscaling Utility (main.js)

Downscale images to max 768px on longest dimension to reduce CLI latency:

```javascript
const { nativeImage } = require('electron');

function downscaleImage(imageBuffer, maxDimension = 768) {
  const image = nativeImage.createFromBuffer(imageBuffer);
  const size = image.getSize();

  if (size.width <= maxDimension && size.height <= maxDimension) {
    return image.toPNG();
  }

  const scale = maxDimension / Math.max(size.width, size.height);
  const newWidth = Math.round(size.width * scale);
  const newHeight = Math.round(size.height * scale);

  const resized = image.resize({ width: newWidth, height: newHeight });
  return resized.toPNG();
}
```

### 3. IPC Handler: Save Image (main.js)

```javascript
ipcMain.handle('save-temp-image', async (event, { buffer, type = 'reference' }) => {
  try {
    ensureTempDir();

    imageCounter++;
    const prefix = type === 'viewport' ? 'viewport' : 'img';
    const filename = `${prefix}_${String(imageCounter).padStart(3, '0')}.png`;
    const filepath = path.join(TEMP_IMAGE_DIR, filename);

    // Downscale if needed
    const imageBuffer = Buffer.from(buffer);
    const processedBuffer = downscaleImage(imageBuffer);

    fs.writeFileSync(filepath, processedBuffer);

    console.log(`[Main] Saved image: ${filepath}`);

    return {
      success: true,
      path: filepath,
      number: imageCounter,
      filename
    };
  } catch (err) {
    console.error('[Main] Save image error:', err);
    return {
      success: false,
      error: err.message
    };
  }
});
```

### 4. IPC Handler: Get Temp Directory Path (main.js)

```javascript
ipcMain.handle('get-temp-image-dir', () => {
  ensureTempDir();
  return TEMP_IMAGE_DIR;
});
```

### 5. IPC Handler: Clear Images (main.js)

```javascript
ipcMain.handle('clear-temp-images', () => {
  clearTempDir();
  return { success: true };
});
```

