# Phase 8 Task 4: Images in Message Bubbles

## CONTEXT
When a message is sent with pending images, the images should appear in the user's message bubble. The images are also included in the data sent to Claude.

## REQUIREMENTS

### 1. Modify sendChatMessage (renderer.js)

Capture pending images before sending:

```javascript
async function sendChatMessage() {
  const message = chatInput.value.trim();
  if (!message && pendingImages.length === 0) return;
  if (isProcessing) return;

  // Capture images before clearing
  const imagesToSend = [...pendingImages];
  const imagePaths = imagesToSend.map(img => ({
    number: img.number,
    path: img.path
  }));

  chatInput.value = '';
  clearPendingImages();
  isProcessing = true;

  // Add user message with images
  addMessage('user', message, { images: imagesToSend });

  // ... rest of send logic, passing imagePaths to IPC
}
```

### 2. Modify addMessage to Support Images (renderer.js)

```javascript
function addMessage(role, content, options = {}) {
  const message = { role, content, timestamp: new Date(), ...options };

  if (role === 'user' || role === 'assistant') {
    // Store for history (without thumbnail URLs)
    const historyMessage = {
      role,
      content,
      images: options.images?.map(img => ({ number: img.number, path: img.path }))
    };
    messageHistory.push(historyMessage);
  }

  const messageEl = document.createElement('div');
  messageEl.className = `chat-message ${role}`;

  // Add images if present
  if (options.images && options.images.length > 0) {
    const imagesContainer = document.createElement('div');
    imagesContainer.className = 'message-images';

    for (const img of options.images) {
      const imgWrapper = document.createElement('div');
      imgWrapper.className = 'message-image-item';

      const imgEl = document.createElement('img');
      imgEl.src = img.thumbnail;
      imgEl.alt = `Image ${img.number}`;

      const numberEl = document.createElement('span');
      numberEl.className = 'message-image-number';
      numberEl.textContent = img.number;

      imgWrapper.appendChild(imgEl);
      imgWrapper.appendChild(numberEl);
      imagesContainer.appendChild(imgWrapper);
    }

    messageEl.appendChild(imagesContainer);
  }

  // Add text content
  if (content) {
    const contentEl = document.createElement('div');
    contentEl.className = 'message-content';
    // ... existing content handling (markdown, code blocks, etc.)
    messageEl.appendChild(contentEl);
  }

  chatMessagesContainer.appendChild(messageEl);
  messageEl.scrollIntoView({ behavior: 'smooth', block: 'end' });
}
