# Phase 8 Task 6: Viewport Screenshot Capture

## CONTEXT
For autonomous iteration, we need to capture the Three.js viewport as an image. This task adds the capture function. The next task adds a manual "Capture View" button.

## REQUIREMENTS

### 1. Capture Function (renderer.js)

```javascript
/**
 * Capture the current viewport as a PNG buffer
 * @returns {Promise<Uint8Array>} PNG image data
 */
async function captureViewport() {
  // Ensure we have a fresh render
  renderer.render(scene, camera);

  // Get canvas data
  const canvas = renderer.domElement;

  return new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (!blob) {
        reject(new Error('Failed to capture viewport'));
        return;
      }

      blob.arrayBuffer().then(buffer => {
        resolve(new Uint8Array(buffer));
      }).catch(reject);
    }, 'image/png');
  });
}
```

### 2. Save Viewport Screenshot Function (renderer.js)

```javascript
/**
 * Capture viewport and save to temp directory
 * @returns {Promise<{number, path, thumbnail}>} Image info
 */
async function saveViewportScreenshot() {
  try {
    const buffer = await captureViewport();

    const result = await ipcRenderer.invoke('save-temp-image', {
      buffer: Array.from(buffer),
      type: 'viewport'
    });

    if (!result.success) {
      throw new Error(result.error);
    }

    // Create thumbnail URL from the buffer
    const blob = new Blob([buffer], { type: 'image/png' });
    const thumbnail = URL.createObjectURL(blob);

    return {
      number: result.number,
      path: result.path,
      thumbnail
    };
  } catch (err) {
    console.error('[Renderer] Viewport capture error:', err);
    throw err;
  }
}
```

### 3. Ensure Transparent Background Handling

Three.js may render with transparent background. Ensure we have a solid background for the screenshot:

```javascript
// In captureViewport, temporarily ensure background is visible
async function captureViewport() {
  // Store original clear color
  const originalClearColor = renderer.getClearColor(new THREE.Color());
  const originalClearAlpha = renderer.getClearAlpha();

  // Set solid background for screenshot
  renderer.setClearColor(0x1e1e1e, 1);  // Match app background

  // Render
  renderer.render(scene, camera);

  // Capture
  const canvas = renderer.domElement;

  return new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      // Restore original clear color
      renderer.setClearColor(originalClearColor, originalClearAlpha);

      if (!blob) {
        reject(new Error('Failed to capture viewport'));
        return;
      }

      blob.arrayBuffer().then(buffer => {
        resolve(new Uint8Array(buffer));
      }).catch(reject);
    }, 'image/png');
  });
}
```

