# Phase 8 Task 10: Iteration Loop Driver

## CONTEXT
This is the core of autonomous iteration. The loop:
1. Captures viewport
2. Sends iteration prompt to Claude
3. Validates response
4. Executes new code
5. Checks stop conditions
6. Repeats

## REQUIREMENTS

### 1. IPC Handler for Iteration Step (main.js)

```javascript
ipcMain.handle('run-iteration-step', async (event, {
  originalRequest,
  referenceImages,
  viewportPath,
  viewportNumber,
  currentCode,
  iteration,
  maxIterations
}) => {
  try {
    // Build iteration prompt
    const prompt = claudeManager.buildIterationPrompt({
      originalRequest,
      referenceImages,
      viewportPath,
      viewportNumber,
      currentCode,
      iteration,
      maxIterations
    });

    // Send to Claude
    const rawResponse = await claudeManager.sendPrompt(prompt, TEMP_IMAGE_DIR);

    // Parse response
    const parsed = claudeManager.parseIterationResponse(rawResponse);

    if (parsed.type === 'no_changes') {
      return {
        success: true,
        type: 'no_changes',
        message: 'Claude determined the model matches the reference.'
      };
    }

    if (parsed.type === 'invalid') {
      return {
        success: false,
        type: 'invalid',
        error: 'Claude response did not match expected format.',
        raw: parsed.raw
      };
    }

    // Execute the new code
    const execResult = await pythonManager.executeCode(parsed.code);

    if (!execResult.success) {
      return {
        success: false,
        type: 'execution_error',
        error: execResult.error,
        code: parsed.code
      };
    }

    return {
      success: true,
      type: 'code',
      code: parsed.code,
      shapes: execResult.shapes,
      volume: execResult.volume
    };
  } catch (err) {
    console.error('[Main] Iteration step error:', err);
    return {
      success: false,
      type: 'error',
      error: err.message
    };
  }
});
```

### 2. Main Loop Function (renderer.js)

```javascript
async function startIterationLoop() {
  // Capture state at start
  const maxIterations = parseInt(document.getElementById('max-iterations-input')?.value || '10');
  const referenceImages = pendingImages.map(img => ({ number: img.number, path: img.path }));
  const originalRequest = document.getElementById('chat-input').value.trim();

  // Clear input and pending images
  document.getElementById('chat-input').value = '';
  clearPendingImages();

  // Initialize state
  iterationState = {
    active: true,
    current: 0,
    max: maxIterations,
    stopRequested: false,
    referenceImages,
    originalRequest,
    previousCode: currentCode,
    unchangedCount: 0
  };

  // Show UI
  showIterationUI();
  addMessage('system', `Starting autonomous iteration (max ${maxIterations}). Click Stop to halt.`);

  // If no current code, generate initial version first
  if (!currentCode) {
    addMessage('system', 'Generating initial model...');
    // Could do initial generation here, or let first iteration handle it
  }

  try {
    for (let i = 1; i <= maxIterations; i++) {
      // Check stop request
      if (iterationState.stopRequested) {
        addMessage('system', `Stopped at iteration ${i - 1}.`);
        break;
      }

      iterationState.current = i;
      updateIterationCounter(i, maxIterations);

      // 1. Capture current viewport
      setProcessing('Capturing viewport...');
      const viewport = await saveViewportScreenshot();

      // 2. Run iteration step
      setProcessing(`Iteration ${i}: Asking Claude...`);

      const result = await ipcRenderer.invoke('run-iteration-step', {
        originalRequest,
        referenceImages,
        viewportPath: viewport.path,
        viewportNumber: viewport.number,
        currentCode,
        iteration: i,
        maxIterations
      });

      // Clean up viewport thumbnail
      URL.revokeObjectURL(viewport.thumbnail);

      // 3. Handle result
      if (result.type === 'no_changes') {
        addMessage('assistant', 'Model matches reference. Stopping iteration.');
        break;
      }

      if (!result.success) {
        addMessage('error', `Iteration ${i} failed: ${result.error}`);
        // Continue trying unless it's a critical error
        if (result.type === 'error') break;
        continue;
      }

      // 4. Check for unchanged code (oscillation detection)
      if (result.code === iterationState.previousCode) {
        iterationState.unchangedCount++;
        if (iterationState.unchangedCount >= 2) {
          addMessage('system', 'Code unchanged for 2 iterations. Stopping.');
          break;
        }
      } else {
        iterationState.unchangedCount = 0;
      }
      iterationState.previousCode = result.code;

      // 5. Update model
      currentCode = result.code;
      await loadShapes(result.shapes, result.volume);

      addMessage('system', `Iteration ${i} complete.`);

      // Small delay to allow UI to update
      await new Promise(resolve => setTimeout(resolve, 100));
    }
  } catch (err) {
    addMessage('error', `Iteration loop error: ${err.message}`);
  } finally {
    // Cleanup
    iterationState.active = false;
    hideIterationUI();
    setProcessing(null);
    addMessage('system', `Iteration complete. Final result after ${iterationState.current} iterations.`);
  }
}
```

